class BookMyShow:

    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        self.seats = [[True]*m for _ in range(n)]

    def gather(self, k: int, maxRow: int) -> List[int]:
        for i in range(min(maxRow+1, self.n)):
            for j in range(self.m-k+1):
                if all(self.seats[i][j+l] for l in range(k)):
                    for l in range(k):
                        self.seats[i][j+l] = False
                    return [i, j]
        return []

    def scatter(self, k: int, maxRow: int) -> bool:
        count = 0
        for i in range(min(maxRow+1, self.n)):
            for j in range(self.m):
                if self.seats[i][j]:
                    self.seats[i][j] = False
                    count += 1
                    if count == k:
                        return True
        return False


